+const GOOGLE_INPUT_TOOLS_URL = "https://inputtools.google.com/request";
+
+function buildPayload({ strokes, width, height, language, preContext = "" }) {
+  return {
+    app_version: 0.4,
+    api_level: "537.36",
+    device: "pretext-handwriting-demo",
+    input_type: 0,
+    options: "enable_pre_space",
+    requests: [
+      {
+        writing_guide: {
+          writing_area_width: Math.max(1, Math.round(width)),
+          writing_area_height: Math.max(1, Math.round(height))
+        },
+        pre_context: preContext,
+        max_num_results: 8,
+        max_completions: 0,
+        language,
+        ink: strokes.map((stroke) => [stroke.x, stroke.y, stroke.t])
+      }
+    ]
+  };
+}
+
+function parseResponse(payload) {
+  if (!Array.isArray(payload) || payload[0] !== "SUCCESS") {
+    const message = Array.isArray(payload) ? payload[0] : "Unexpected response";
+    throw new Error(`Google Input Tools request failed: ${message}`);
+  }
+
+  const firstResult = payload[1]?.[0];
+  const candidates = firstResult?.[1] ?? [];
+
+  return {
+    text: candidates[0] ?? "",
+    candidates
+  };
+}
+
+export async function recognizeHandwriting({ strokes, width, height, language }) {
+  const payload = buildPayload({ strokes, width, height, language });
+  const params = new URLSearchParams({
+    itc: `${language}-t-i0-handwrit`,
+    app: "demopage"
+  });
+
+  const response = await fetch(`${GOOGLE_INPUT_TOOLS_URL}?${params.toString()}`, {
+    method: "POST",
+    headers: {
+      "Content-Type": "application/json; charset=UTF-8"
+    },
+    body: JSON.stringify(payload)
+  });
+
+  if (!response.ok) {
+    throw new Error(`Google Input Tools HTTP ${response.status}`);
+  }
+
+  const data = await response.json();
+  return parseResponse(data);
+}
*** Add File: server/index.js
+import express from "express";
+import path from "node:path";
+import { fileURLToPath } from "node:url";
+
+import { recognizeHandwriting } from "./google-input-tools.js";
+
+const __filename = fileURLToPath(import.meta.url);
+const __dirname = path.dirname(__filename);
+const publicDir = path.join(__dirname, "..", "public");
+
+const app = express();
+const port = Number(process.env.PORT) || 3000;
+
+app.use(express.json({ limit: "1mb" }));
+app.use(express.static(publicDir));
+
+app.post("/api/recognize/draw", async (req, res) => {
+  const { strokes, width, height, language = "en" } = req.body ?? {};
+
+  if (!Array.isArray(strokes) || strokes.length === 0) {
+    return res.status(400).json({ error: "At least one stroke is required." });
+  }
+
+  const invalidStroke = strokes.some((stroke) => {
+    return !stroke || !Array.isArray(stroke.x) || !Array.isArray(stroke.y) || !Array.isArray(stroke.t);
+  });
+
+  if (invalidStroke) {
+    return res.status(400).json({ error: "Each stroke must provide x, y, and t arrays." });
+  }
+
+  try {
+    const result = await recognizeHandwriting({ strokes, width, height, language });
+    return res.json(result);
+  } catch (error) {
+    return res.status(502).json({
+      error: error instanceof Error ? error.message : "Recognition failed."
+    });
+  }
+});
+
+app.listen(port, () => {
+  console.log(`Handwriter running at http://localhost:${port}`);
+});
