    this.clearButton = clearButton;
    this.resultView = resultView;

    this.onRecognize = this.onRecognize.bind(this);
    this.onClear = this.onClear.bind(this);
  }

  mount() {
    this.recognizeButton.addEventListener("click", this.onRecognize);
    this.clearButton.addEventListener("click", this.onClear);
  }

  async onRecognize() {
    if (!this.strokeCanvas.hasInk()) {
      this.resultView.setStatus("Draw something before running recognition.");
      return;
    }

    this.recognizeButton.disabled = true;
    this.resultView.setStatus("Recognizing handwriting...");

    try {
      const payload = {
        ...this.strokeCanvas.getPayload(),
        language: this.languageSelect.value
      };

      const result = await this.recognitionApi.recognizeDrawInput(payload);
      this.resultView.setResultText(result.text || "No text recognized.");
      this.resultView.setCandidates(result.candidates || []);
      this.resultView.setStatus("Recognition complete.");
    } catch (error) {
      this.resultView.setResultText("Recognition failed.");
      this.resultView.setCandidates([]);
      this.resultView.setStatus(error instanceof Error ? error.message : "Recognition failed.");
    } finally {
      this.recognizeButton.disabled = false;
    }
  }

  onClear() {
    this.strokeCanvas.clear();
    this.resultView.setResultText("Nothing recognized yet.");
    this.resultView.setCandidates([]);
    this.resultView.setStatus("Canvas cleared.");
  }
}

function createEmptyStroke() {
  return { x: [], y: [], t: [] };
}

export class StrokeCanvas {
  constructor(canvas) {
    this.canvas = canvas;
    this.context = canvas.getContext("2d");
    this.context.lineCap = "round";
    this.context.lineJoin = "round";
    this.context.strokeStyle = "#111827";
    this.context.lineWidth = 4;

    this.strokes = [];
    this.currentStroke = null;
    this.pointerId = null;
    this.sessionStart = 0;

    this.resize = this.resize.bind(this);
    this.onPointerDown = this.onPointerDown.bind(this);
    this.onPointerMove = this.onPointerMove.bind(this);
    this.onPointerUp = this.onPointerUp.bind(this);

    window.addEventListener("resize", this.resize);
    this.canvas.addEventListener("pointerdown", this.onPointerDown);
    this.canvas.addEventListener("pointermove", this.onPointerMove);
    this.canvas.addEventListener("pointerup", this.onPointerUp);
    this.canvas.addEventListener("pointerleave", this.onPointerUp);
    this.canvas.addEventListener("pointercancel", this.onPointerUp);

    this.resize();
    this.clear();
  }

  resize() {
    const rect = this.canvas.getBoundingClientRect();
    const ratio = window.devicePixelRatio || 1;
    this.canvas.width = Math.round(rect.width * ratio);
    this.canvas.height = Math.round(rect.height * ratio);
    this.context.setTransform(ratio, 0, 0, ratio, 0, 0);
    this.redraw();
  }

  clear() {
    this.strokes = [];
    this.currentStroke = null;
    this.pointerId = null;
    this.sessionStart = 0;
    this.redraw();
  }

  hasInk() {
    return this.strokes.length > 0;
  }

  getPayload() {
    return {
      width: this.canvas.clientWidth,
      height: this.canvas.clientHeight,
      strokes: this.strokes
    };
  }

  toPoint(event) {
    const rect = this.canvas.getBoundingClientRect();
    return {
      x: Math.round(event.clientX - rect.left),
      y: Math.round(event.clientY - rect.top),
      t: Math.round(performance.now() - this.sessionStart)
    };
  }

  beginStroke(event) {
    if (!this.sessionStart) {
      this.sessionStart = performance.now();
    }

    this.currentStroke = createEmptyStroke();
    this.strokes.push(this.currentStroke);
    this.addPoint(event);
  }

  addPoint(event) {
    if (!this.currentStroke) {
      return;
    }

    const point = this.toPoint(event);
    this.currentStroke.x.push(point.x);
    this.currentStroke.y.push(point.y);
    this.currentStroke.t.push(point.t);
    this.redraw();
  }

  endStroke() {
    this.currentStroke = null;
    this.pointerId = null;
  }

  onPointerDown(event) {
    event.preventDefault();

    this.pointerId = event.pointerId;
    this.canvas.setPointerCapture(event.pointerId);
    this.beginStroke(event);
  }

  onPointerMove(event) {
    if (event.pointerId !== this.pointerId || !this.currentStroke) {
      return;
    }

    event.preventDefault();
    this.addPoint(event);
  }

  onPointerUp(event) {
    if (event.pointerId !== this.pointerId) {
      return;
    }

    event.preventDefault();
    this.endStroke();
  }

  redraw() {
    const width = this.canvas.clientWidth;
    const height = this.canvas.clientHeight;

    this.context.clearRect(0, 0, width, height);
    this.context.fillStyle = "#fffef8";
    this.context.fillRect(0, 0, width, height);

    for (const stroke of this.strokes) {
      if (stroke.x.length === 0) {
        continue;
      }

      this.context.beginPath();
      this.context.moveTo(stroke.x[0], stroke.y[0]);

      if (stroke.x.length === 1) {
        this.context.lineTo(stroke.x[0] + 0.01, stroke.y[0] + 0.01);
      }

      for (let i = 1; i < stroke.x.length; i += 1) {
        this.context.lineTo(stroke.x[i], stroke.y[i]);
      }

      this.context.stroke();
    }
  }
}

import { StrokeCanvas } from "./lib/stroke-canvas.js";
import { ResultView } from "./lib/result-view.js";
import { DrawMode } from "./modes/draw-mode.js";
import { ModeSwitcher } from "./modes/mode-switcher.js";
import { UploadMode } from "./modes/upload-mode.js";
import { RecognitionApi } from "./services/recognition-api.js";

const strokeCanvas = new StrokeCanvas(document.querySelector("#draw-canvas"));
const recognitionApi = new RecognitionApi();
const resultView = new ResultView({
  resultText: document.querySelector("#result-text"),
  candidateList: document.querySelector("#candidate-list"),
  status: document.querySelector("#status")
});

const drawMode = new DrawMode({
  strokeCanvas,
  recognitionApi,
  languageSelect: document.querySelector("#language-select"),
  recognizeButton: document.querySelector("#recognize-button"),
  clearButton: document.querySelector("#clear-button"),
  resultView
});

const uploadMode = new UploadMode({
  recognitionApi,
  fileInput: document.querySelector("#image-file"),
  uploadButton: document.querySelector("#upload-recognize-button"),
  clearButton: document.querySelector("#upload-clear-button"),
  previewImage: document.querySelector("#upload-preview-image"),
  fileName: document.querySelector("#image-file-name"),
  resultView
});

const modeSwitcher = new ModeSwitcher({
  buttons: {
    draw: document.querySelector("#mode-draw-button"),
    upload: document.querySelector("#mode-upload-button")
  },
  panels: {
    draw: document.querySelector("#draw-panel"),
    upload: document.querySelector("#upload-panel")
  },
  title: document.querySelector("#mode-title"),
  hint: document.querySelector("#mode-hint"),
  resultView,
  onModeChange: (mode) => {
    if (mode === "draw") {
      strokeCanvas.resize();
    }
  }
});

drawMode.mount();
uploadMode.mount();
modeSwitcher.mount();

